;; const int op::transfer

() recv_internal(int my_balance, int msg_value, cell in_msg_full, slice in_msg_body) impure {
    slice cs = in_msg_full.begin_parse();
    int flags = cs~load_uint(4);
    ;; ignore all bounced messages
    if (is_bounced?(flags)) {
        return ();
    }
    slice sender_address = cs~load_msg_addr();

    (int op, int query_id) = in_msg_body~load_op_and_query_id();

    if (op == op::withdraw) {
        ;; Load owner address from storage for access control
        slice ds = get_data().begin_parse();
        slice owner_address = ds~load_msg_addr();

        ;; Verify sender is authorized
        throw_unless(404, equal_slices(sender_address, owner_address));

        int amount = in_msg_body~load_coins();
        slice to_address = in_msg_body~load_msg_addr();
        int forward_ton_amount = in_msg_body~load_coins();
        cell forward_payload = begin_cell().store_slice(in_msg_body).end_cell();

        ;; Validate amount to prevent excessive withdrawals
        throw_unless(402, amount > 0);
        throw_unless(403, amount <= 1000000000000); ;; Max 1000 jettons (assuming 9 decimals)

        ;; Validate forward_ton_amount to prevent excessive values
        throw_unless(401, forward_ton_amount <= 100000000); ;; Max 0.1 TON

        var msg_body = begin_cell()
            .store_op_and_query_id(op::transfer, query_id)
            .store_coins(amount)
            .store_slice(to_address)
            .store_slice(to_address)
            .store_uint(0, 1)
            .store_coins(forward_ton_amount) ;; Already validated above
            .store_maybe_ref(forward_payload)
            .end_cell();

        cell msg = begin_cell()
            .store_uint(0x18, 6)
            .store_slice(USDT_WALLET_ADDRESS)
            .store_coins(JETTON_TRANSFER_GAS) ;; Use only constant, not user input
            .store_uint(1, 1 + 4 + 4 + 64 + 32 + 1 + 1)
            .store_ref(msg_body)
            .end_cell();

        send_raw_message(msg, 0);

        return ();
    }
}

